/**
 * calligraphy.js — SVG glyph renderer for Blackscale Consulting
 * All 71 glyphs are embedded as base64 data URIs (no external file loads).
 * Replaces <em> text inside h1/h2 headings with hand-lettered calligraphic SVG glyphs.
 * window.applyCalligraphy() is called by translations.js after each lang switch.
 */
